{
  "sentences": [
    {
      "text": "不好意思，我想要一杯小杯的拿鐵。",
      "pinyin": "Bù hǎo yì si, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de0 na2 tie3.",
      "translation_en": "Excuse me, I would like a small latte.",
      "translation_ko": "실례합니다, 작은 라떼 한 잔을 원합니다."
    },
    {
      "text": "不好意思，麻煩給我一個袋子。",
      "pinyin": "Bù hǎo yì si, má fan gěi wǒ yī ge dài zi.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ma2 fan0 gei3 wo3 yi1 ge0 dai4 zi0.",
      "translation_en": "Excuse me, could you give me a bag, please?",
      "translation_ko": "실례합니다, 봉투 하나 주시겠어요?"
    },
    {
      "text": "不好意思，我要一杯紅茶，半糖少冰。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi hóng chá, bàn táng shǎo bīng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 hong2 cha2, ban4 tang2 shao3 bing1.",
      "translation_en": "Excuse me, I'd like a black tea, half sugar and less ice.",
      "translation_ko": "실례합니다, 홍차 한 잔에 당 반만 넣고 얼음 적게 해주세요."
    },
    {
      "title": "不好意思，請問這個價錢是多少？",
      "pinyin": "Bù hǎo yì si, qǐng wèn zhè ge jià qián shì duō shǎo?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, qing3 wen4 zhe4 ge0 jia4 qian2 shi4 duo1 shao3?",
      "translation_en": "Excuse me, how much is this?",
      "translation_ko": "실례합니다, 이 가격이 얼마인가요?"
    },
    {
      "text": "不好意思，我要一杯綠茶，去冰。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi lǜ chá, qù bīng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 lü4 cha2, qu4 bing1.",
      "translation_en": "Excuse me, I'd like a green tea, no ice.",
      "translation_ko": "실례합니다, 녹차 한 잔에 얼음 빼주세요."
    },
    {
      "text": "不好意思，麻煩幫我加珍珠。",
      "pinyin": "Bù hǎo yì si, má fan bāng wǒ jiā zhēn zhū.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ma2 fan0 bang1 wo3 jia1 zhen1 zhu1.",
      "translation_en": "Excuse me, please add boba for me.",
      "translation_ko": "실례합니다, 타피오카 펄을 추가해 주세요."
    },
    {
      "text": "不好意思，我要外帶一杯豆漿。",
      "pinyin": "Bù hǎo yì si, wǒ yào wài dài yī bēi dòu jiāng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 wai4 dai4 yi1 bei1 dou4 jiang1.",
      "translation_en": "Excuse me, I'd like a soy milk to go.",
      "translation_ko": "실례합니다, 두유 한 잔 포장해 주세요."
    },
    {
      "text": "不好意思，請給我一根吸管。",
      "pinyin": "Bù hǎo yì si, qǐng gěi wǒ yī gēn xī guǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, qing3 gei3 wo3 yi1 gen1 xi1 guan3.",
      "translation_en": "Excuse me, please give me a straw.",
      "translation_ko": "실례합니다, 빨대 하나 주세요."
    },
    {
      "text": "不好意思，我要內用，等一下再點。",
      "pinyin": "Bù hǎo yì si, wǒ yào nèi yòng, děng yī xià zài diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 nei4 yong4, deng3 yi1 xia4 zai4 dian3.",
      "translation_en": "Excuse me, I'll eat here and order later.",
      "translation_ko": "실례합니다, 매장에서 먹을게요. 잠시 후에 주문할게요."
    },
    {
      "text": "不好意思，麻煩再說一次，慢一點。",
      "pinyin": "Bù hǎo yì si, má fan zài shuō yī cì, màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ma2 fan0 zai4 shuo1 yi1 ci4, man4 yi1 dian3.",
      "translation_en": "Excuse me, please say it again, slower.",
      "translation_ko": "실례합니다, 한 번 더 말씀해 주세요, 천천히요."
    }
  ]
}
